package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Method;

import com.google.gson.ReflectionAccessFilter;
import com.google.gson.ReflectionAccessFilter.FilterResult;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.MockedStatic;
import org.mockito.junit.jupiter.MockitoExtension;

@ExtendWith(MockitoExtension.class)
class ReflectionAccessFilterHelperTest {

  @Test
  void canAccess_returnsTrue_whenAccessCheckerReturnsTrue() throws Exception {
    AccessibleObject accessibleObject = mock(AccessibleObject.class);
    Object obj = new Object();

    Class<?> accessCheckerClass = Class.forName("com.google.gson.internal.AccessChecker");
    Method canAccessMethod = accessCheckerClass.getMethod("canAccess", AccessibleObject.class, Object.class);

    try (MockedStatic<?> accessCheckerMockedStatic = mockStatic(accessCheckerClass)) {
      Object mockInstance = mock(accessCheckerClass);
      accessCheckerMockedStatic.when(() -> accessCheckerClass.getField("INSTANCE").get(null)).thenReturn(mockInstance);

      // Mock canAccess to return true when called with accessibleObject and obj
      when(canAccessMethod.invoke(mockInstance, accessibleObject, obj)).thenReturn(true);

      // Because invoke calls the real method, we cannot mock invoke directly.
      // Instead, use Mockito doAnswer on mockInstance's canAccess method via reflection proxy:

      // Use Mockito's Answer with doAnswer on mockInstance proxy:
      doAnswer(invocation -> true)
          .when(mockInstance)
          .getClass()
          .getMethod("canAccess", AccessibleObject.class, Object.class)
          .invoke(mockInstance, accessibleObject, obj);

      // The above still invokes the real method, so better to use a proxy that intercepts calls.

      // Instead, create a proxy instance implementing AccessChecker interface via reflection:

      Object proxyInstance = java.lang.reflect.Proxy.newProxyInstance(
          accessCheckerClass.getClassLoader(),
          new Class<?>[]{accessCheckerClass},
          (proxy, method, args) -> {
            if ("canAccess".equals(method.getName())
                && args.length == 2
                && args[0] == accessibleObject
                && args[1] == obj) {
              return true;
            }
            return method.invoke(mockInstance, args);
          });

      accessCheckerMockedStatic.when(() -> accessCheckerClass.getField("INSTANCE").get(null)).thenReturn(proxyInstance);

      // Now call the method under test
      boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObject, obj);
      assertTrue(result);
    }
  }

  @Test
  void canAccess_returnsFalse_whenAccessCheckerReturnsFalse() throws Exception {
    AccessibleObject accessibleObject = mock(AccessibleObject.class);
    Object obj = new Object();

    Class<?> accessCheckerClass = Class.forName("com.google.gson.internal.AccessChecker");

    try (MockedStatic<?> accessCheckerMockedStatic = mockStatic(accessCheckerClass)) {
      Object mockInstance = mock(accessCheckerClass);

      Object proxyInstance = java.lang.reflect.Proxy.newProxyInstance(
          accessCheckerClass.getClassLoader(),
          new Class<?>[]{accessCheckerClass},
          (proxy, method, args) -> {
            if ("canAccess".equals(method.getName())
                && args.length == 2
                && args[0] == accessibleObject
                && args[1] == obj) {
              return false;
            }
            return method.invoke(mockInstance, args);
          });

      accessCheckerMockedStatic.when(() -> accessCheckerClass.getField("INSTANCE").get(null)).thenReturn(proxyInstance);

      boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObject, obj);
      assertFalse(result);
    }
  }

  @Test
  void privateConstructor_isPrivate() throws Exception {
    var constructor = ReflectionAccessFilterHelper.class.getDeclaredConstructor();
    assertTrue((constructor.getModifiers() & java.lang.reflect.Modifier.PRIVATE) != 0);
    constructor.setAccessible(true);
    constructor.newInstance();
  }
}
